module top_module(
    input clk,
    input din,
    output dout,
    input reset_n
);// Replacing wasca_altpll_1_dffpipe_l2c with a standard D flip-flop design.
reg dff_sync_reg;

// D flip-flop implementation
always @(posedge clk or negedge reset_n) begin
    if (!reset_n)
        dff_sync_reg <= 1'b0; // Reset to 0 on reset
    else
        dff_sync_reg <= din; // Capture input data
end

assign dout = dff_sync_reg;

endmodule
